var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"부상은 어떤가요, 리코리스?","JPN":"怪我はどうですか、リコリス？","ENG":"How’s the wound, Lycoris?","TWN":"傷勢怎麼樣，莉克麗絲？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"보면 알잖아. 아야야야…….","JPN":"みりゃわかるでしょ。いててて……","ENG":"You’re looking at it already. Awwww...","TWN":"看也知道吧？哎唷唷唷…"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"시간을 끌다가 물러나면 된다고 그렇게 말했는데, 왜 제 지시를 안 들었죠?","JPN":"時間稼ぎだけできたら撤退していいと言ったのに、なぜ私の指示に従わなかったのですか？","ENG":"I told to not to overstay. Why didn’t you listen?","TWN":"我不是說稍微拖延一下時間就撤嗎？為什麼不聽？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"빨래를 돕는 동안 모네한테서 바보가 옮기라도 했나요?","JPN":"洗濯を手伝っている間、モネからおバカウイルスでももらったんですか？","ENG":"Did you pick up Mone’s foolishness when you were doing laundry together?","TWN":"你是莫妮不在的時候幫忙洗衣服，就變得更莫妮一樣傻嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 착각하지 마. 그냥 그 물갈퀴 달고 다니는 애가 마음에 안 들었을 뿐이니까.","JPN":"ふん、勘違いしないで。あの水かきをつけてる子が気に入らなかっただけだから。","ENG":"Hmpf, it’s not that. I just didn’t like the girl with grappling hooks.","TWN":"哼，不要誤會。我只是不喜歡那個帶著魚叉的女生而已。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"그렇다고 하기엔 온 산에 다 들리게 외치던데요.","JPN":"そういうわりにはこの一帯に響くらい叫んでましたよ。","ENG":"Yet I could hear you shouting out all over the mountain.","TWN":"但是你剛叫得整座山都有聽到。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"<color=#ffd34c>그래도 한식구인 애가 휴가 날에 울상 짓는 꼴은 보기 싫다고!</color> 라고.","JPN":"<color=#ffd34c>でも、家族同然の子がせっかく帰省したのに、泣きそうな顔をするのは見たくないの！</color>　って。","ENG":"<color=#ffd34c>But still, I don’t want to see my colleague getting all teary while she’s on vacation!</color>","TWN":"<color=#ffd34c>但我不樂意見到人家的孩子在休假時哭喪著臉！！</color>。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"하, 한창 싸우고 있을 때 그걸 네가 어떻게 들었어?!","JPN":"た、戦いの真っ最中だったのになんであんたが聞いてるわけ！？","ENG":"H-how did you hear that? You must have been busy fighting yourself!","TWN":"你…你不是忙著對付作戰嗎？怎麼聽到的？！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"메이드는 항상 귀를 열어 놓고 있어야 합니다. 주인님의 부름은 언제 들릴지 모르거든요.","JPN":"メイドは常に耳を開けておかなければなりません。ご主人様にいつ呼ばれるかわかりませんので。","ENG":"A maid must be aware of everything around her. You never know when the Master will call on you.","TWN":"女僕就是要時時刻刻打開耳朵，才能隨時聽到主人的吩咐。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"하지만 리코리스는 역시 주방보다는 육아 담당이 적합해요. 메이드장님께 건의드리겠습니다.","JPN":"しかし、リコリスはやはりキッチンより育児担当に向いています。メイド長に提案します。","ENG":"I think you are better at baby-sitting rather than kitchen work. I’ll propose a change of assignment to the Chief Maid.","TWN":"不過我看你好像不太適合廚房的工作，保母比較適合你，我會再向女僕長提出建議。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"야! 너 그러면 진짜 가만 안 둬!","JPN":"ねえ！　絶対にやめてよ！","ENG":"Hey! I will never let you do that!","TWN":"喂！你敢的話我可不會放過你！"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_Q","text":{"KOREA":"그 건의는 보류해야겠어요, 릴리.","JPN":"その提案は保留にしますね、リリー。","ENG":"I’ll have to put your proposal on hold, Lily.","TWN":"莉莉，你的建議我先暫時保留。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_Q","text":{"KOREA":"주인님을 섬기는 방식은 리코리스 스스로 택해야 하니까요.","JPN":"ご主人様に仕える仕事は、リコリスがみずから選ぶ必要がありますから。","ENG":"Lycoris has the right to choose how she serves the master.","TWN":"因爲服侍主人的方式，應該由莉克麗絲自己選擇。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하하핫! 그 얼빠진 표정은 뭐야?","JPN":"キャハハハ！　なんだ、そのマヌケな顔！","ENG":"Kya hah hah! What’s with that look on your face?","TWN":"哈哈哈哈！看你們一副恍神的樣子！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"설마 그 둘이서 어떻게 할 수 있다고 생각한 건 아니겠지?","JPN":"まさか二人だけでどうにかなると思ったの？","ENG":"You didn’t think they could handle me, did you?","TWN":"你們該不會以為他們兩個會有什麼對策嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"나, 나쁜 언니가 나타났슴다!","JPN":"わ、悪いお姉さんが現れたっす！","ENG":"The mean lady is here!","TWN":"是…壞姊姊！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오! 애꾸눈은 아니지만 역시 훌륭한 악당 해적 웃음소리야!","JPN":"おお！　眼帯はないけど、やっぱり立派な悪党海賊の笑い声だ！","ENG":"Oh! Your laughter is very pirate-ish, even though you don’t have an eye patch!","TWN":"哇喔！雖然不是獨眼龍，但是笑聲確實很像反派海盜！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};